INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b2bc8b3e-8e0f-472e-bce5-2558f22c12fd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tableau to Metabase — Questions, Models, and Signed Embedding Mapped for Tableau Users$escape$,
  $escape$Tableau users approaching Metabase need a mental model remap. Metabase's Questions map to Tableau Worksheets — a GUI query builder for simple charts or a raw SQL editor for custom logic. Dashboards work identically: drag questions onto a canvas, wire up cross-filter parameters, and set auto-refresh intervals. Models are the critical divergence: unlike Tableau's Published Data Sources (Hyper-backed, Prep-managed), Metabase Models are SQL-defined semantic layers stored inside the app itself — no ETL tool required. They persist column metadata and serve as trusted sources for downstream Questions, analogous to Tableau's logical table layer.

For embedding, Metabase uses signed JWT tokens rather than Tableau Server's trusted tickets. Enable embedding under Admin → Settings, generate a 256-bit secret, then sign a payload specifying the resource and any locked parameters. The result is an iframe URL — or, with the JS SDK (beta), a React component. Admin setup mirrors Tableau Server site configuration: connect databases via Admin → Databases, apply row-level sandboxing (Pro+) for data security, and map user groups to collection permissions — the equivalent of Tableau's site roles and project-level permissions.$escape$,
  $escape$import jwt
import time

METABASE_SECRET_KEY = "your-256-bit-secret"
METABASE_SITE_URL = "https://metabase.example.com"

payload = {
    "resource": {"dashboard": 42},
    "params": {"department": ["Engineering"]},
    "exp": round(time.time()) + (60 * 10)  # 10-min expiry
}

token = jwt.encode(payload, METABASE_SECRET_KEY, algorithm="HS256")
iframe_url = f"{METABASE_SITE_URL}/embed/dashboard/{token}#bordered=true&titled=true"
print(iframe_url)$escape$,
  $escape$python$escape$,
