INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '899443da-6716-4895-b4b3-250b5f5e042c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tableau Server Metrics in Grafana — Time-Series Panels, Alerts & Provisioning as Code$escape$,
  $escape$Tableau Server's internal PostgreSQL repository (`workgroup` DB, port 8060) exposes granular session, backgrounder, and VizQL query data that Grafana consumes natively as a time-series datasource. Unlike Tableau's built-in Admin Views — which are themselves Tableau workbooks with fixed granularity — Grafana's Time series panel renders `http_requests.duration_ms` as a true continuous stream with sub-minute resolution. Add a Stat panel for live active session count, a Heatmap for view-load latency distribution across backgrounder workers, and a Bar gauge for extract refresh durations. For alerting, define a Grafana alert rule on `background_jobs` where `finish_code = 1` (failure) exceeds a rolling 5-minute count threshold — this fires before Tableau Server's own Status page reflects the failure. Provision everything as code: drop a datasource YAML and dashboard JSON into `/etc/grafana/provisioning/` and restart. No click-ops, fully version-controlled, and replicable across Tableau Server nodes or forward into a Tableau Cloud migration. This replaces ad-hoc TSM log tailing and manual Admin View exports entirely.$escape$,
  $escape$# /etc/grafana/provisioning/datasources/tableau-repo.yaml
apiVersion: 1
datasources:
  - name: Tableau-Repository
    type: postgres
    url: tableau-server-host:8060
    database: workgroup
    user: tblwgadmin
    secureJsonData:
      password: ${TABLEAU_REPO_PASSWORD}
    jsonData:
      sslmode: require
      postgresVersion: 1400
      timescaledb: false
      timeInterval: "1m"$escape$,
  $escape$bash$escape$,
