INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b78010f2-6f50-4b5a-a5b1-634921be5ec4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tableau Dashboard Design — Information Hierarchy, Cognitive Load, and Storytelling$escape$,
  $escape$Tableau's information hierarchy lives in Layout Containers. Stack a vertical container with KPI scorecards (fixed 80px height) at top, a trend chart in the middle, and a filtered detail table at the bottom — Summary → Context → Detail. Use tiled containers over floating objects on Tableau Server embeds; tiled layouts respect responsive sizing and avoid z-order collisions.

Reduce cognitive load with Tooltip Sheets: build a mini bar chart, then insert it via Edit Tooltip → Insert Sheet. Dense comparisons appear on hover, keeping the canvas clean.

For storytelling, open with BANs using a calculated field: `(SUM([Sales]) - LOOKUP(SUM([Sales]), -1)) / ABS(LOOKUP(SUM([Sales]), -1))` to show Δ% vs prior period. Flow into trend, then breakdown.

Use Dashboard Actions → Filter Action (not Highlight Action) to preserve hierarchy — highlights retain all marks and introduce noise. Set Inner Padding to 4–8px on containers via Format → Dashboard for consistent breathing room, avoiding blank-object hacks that break on Device Designer layouts.$escape$,
  $escape$// Tableau Extensions API — enforce hierarchy filter on dashboard load
tableau.extensions.initializeAsync().then(() => {
  const dash = tableau.extensions.dashboardContent.dashboard;
  const kpiSheet = dash.worksheets.find(w => w.name === "KPI Overview");
  const detailSheet = dash.worksheets.find(w => w.name === "Detail Table");

  // Collapse detail on init; user drills via Filter Action
  detailSheet.applyFilterAsync("Segment", [], tableau.FilterUpdateType.Replace);

  // Seed KPI sheet with current-quarter range
  kpiSheet.applyRangeFilterAsync("Order Date", {
    min: new Date(new Date().getFullYear(), Math.floor(new Date().getMonth() / 3) * 3, 1),
    max: new Date(),
    nullOption: tableau.NullOption.NonNullValues
  }, tableau.FilterUpdateType.Replace);
});$escape$,
  $escape$javascript$escape$,
