INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ea8030a7-3ca6-4546-920c-66312e8ff95f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tableau Interactivity — Parameter Actions, Filter Actions, and Avoiding the Context Re-Query Tax$escape$,
  $escape$Parameter Actions (Tableau 2019.2+) let users update parameter values via click, hover, or menu — no JavaScript needed. The pattern: create a String parameter `[Selected Metric]` with allowable values (Sales, Profit, Quantity), then define a Parameter Action under Dashboard → Actions → Add Action → Change Parameter, targeting that parameter from a dimension field on your chart. Back that with a CASE calculated field:

CASE [Selected Metric]
  WHEN 'Sales' THEN [Sales]
  WHEN 'Profit' THEN [Profit]
  WHEN 'Quantity' THEN [Quantity]
END

Every axis, color encoding, and tooltip reference that field — one click rewires the entire dashboard. For cross-sheet filtering, use Filter Actions (source → target sheet, trigger: Select) rather than stacking Context Filters. Context Filters force a full re-execution of the underlying query, turning an O(1) mark selection into a blocking scan. Prefer Set Actions for multi-sheet coordination when the filtered set is reused across views — sets are computed once and referenced by name, keeping extracts warm. Reserve Context Filters strictly for narrowing fixed-row extracts at load time, not for runtime interactivity.$escape$,
  $escape$// Tableau Embedding API v3 — programmatic filter + parameter control
const viz = document.getElementById('tableauViz');

// Replace active filter on a sheet
await viz.applyFilterAsync(
  'Sub-Category',
  ['Chairs', 'Tables'],
  tableau.FilterUpdateType.Replace
);

// Change a named parameter value
const param = await viz.workbook.findParameterAsync('Selected Metric');
await param.changeValueAsync('Profit');

// Trigger a specific dashboard action by name
await viz.workbook.executeCustomSQLAsync('DrillDown_Action');$escape$,
  $escape$javascript$escape$,
