INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ffe041dc-f388-4f8e-88cd-6d8d94187f78',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tableau Data Freshness — Extract Schedules, Cache Layers, and SLA Monitoring$escape$,
  $escape$Tableau dashboards silently serve stale data when extract refresh schedules aren't tuned. Tableau offers two connection modes: live (queries the source on every interaction) and extract (.hyper file, queried by the in-process Hyper engine). Extracts are significantly faster but introduce lag equal to your refresh cadence.

On Tableau Server/Cloud, scheduled refreshes run as background tasks — configurable per datasource under Data Sources › Schedule. For sub-hourly SLAs, use incremental refreshes instead of full extracts: incremental scans only new rows via an Incremental Refresh Key column, cutting refresh time from minutes to seconds on large sources.

Tableau's caching stack has two layers: the VizQL query cache (shared across users, TTL tunable via tsm configuration set -k vizqlserver.queryCacheMaxSize) and the Hyper model cache (the .hyper file itself). After each refresh completes, hit /views/{id}/image via the REST API to warm the VizQL cache before business hours.

Monitor SLA compliance via datasource.updated_at from the REST API — alert when now() - updated_at exceeds your threshold. Failed background jobs don't surface to end users; polling this field catches silent failures before stakeholders notice stale metrics on production dashboards.$escape$,
  $escape$import tableauserverclient as TSC
from datetime import datetime, timezone, timedelta

server = TSC.Server("https://your-tableau-server", use_server_version=True)
auth = TSC.PersonalAccessTokenAuth("token-name", "token-secret", "site-id")
SLA_HOURS = 4

with server.auth.sign_in(auth):
    all_datasources, _ = server.datasources.get()
    for ds in all_datasources:
        lag = datetime.now(timezone.utc) - ds.updated_at
        if lag > timedelta(hours=SLA_HOURS):
            print(f"SLA BREACH: {ds.name} last refreshed {lag} ago — triggering refresh")
            server.datasources.refresh(ds)$escape$,
  $escape$python$escape$,
