INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '398a6de9-8433-450a-baf5-05bcded05b7a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tableau Row-Level Security — Enforcing User Context in Embedded Dashboards$escape$,
  $escape$Tableau's row-level security hinges on the USERNAME() function paired with a data source filter. Create a calculated field matching a [user_email] column in your entitlements table, then add a data source filter: USERNAME() = [user_email] or ISMEMBEROF("region-west") for group-based access. Every VizQL query Tableau generates appends this filter automatically — users never see out-of-scope rows regardless of URL manipulation.

For embedded analytics, the problem is binding the viewer's real identity to USERNAME(). Tableau Connected Apps solve this: your backend mints a short-lived JWT signed with the Connected App secret, setting the viewer's Tableau Server username in the sub claim. Pass that token to the <tableau-viz> web component's token attribute. Tableau Server validates the signature, resolves sub to a server account, and USERNAME() propagates correctly through every viz on the page.

Avoid the initialSQL user-attribute pattern for RLS — it filters at the database layer and silently breaks with extracts. Data source filters backed by an entitlements table work with both live connections and published extracts, and survive data source promotions across dev/prod environments.$escape$,
  $escape$import jwt, time, uuid

CLIENT_ID = "your-connected-app-client-id"
SECRET_ID = "your-secret-id"
SECRET_VALUE = "your-secret-value"

payload = {
    "iss": CLIENT_ID,
    "exp": int(time.time()) + 300,
    "jti": str(uuid.uuid4()),
    "aud": "tableau",
    "sub": "alice@company.com",
    "scp": ["tableau:views:embed"]
}

token = jwt.encode(
    payload,
    SECRET_VALUE,
    algorithm="HS256",
    headers={"kid": SECRET_ID, "iss": CLIENT_ID}
)$escape$,
  $escape$python$escape$,
