INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '10ce27c5-5995-401e-bdb7-c49ec62ed8a4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tableau Performance — Extracts, Materialized Views, and Why Your Dashboard Is Slow$escape$,
  $escape$Live connections query your database on every interaction — every filter change, every mark selection fires a new SQL round-trip. For high-cardinality dimensions or complex joins, this kills response time. Switch to a Tableau Extract (.hyper) and Hyper's columnar engine handles aggregations in-process, often 10–50x faster than live OLAP queries.

Before reaching for an extract, check your data source first. In Tableau Desktop, open the Performance Recorder (Help → Settings and Performance → Start Performance Recording), interact with the slow view, then stop it. The resulting workbook shows exact query durations — isolate whether the bottleneck is query execution, rendering, or geocoding.

For live connections you can't extract (real-time compliance, row-level security via initial SQL), push the heavy lifting to the database. Create a materialized view over your fact-dimension joins and point Tableau's Custom SQL to it. Use context filters to reduce the initial data scope before dimension filters execute — context filters generate a temp table Tableau queries first, cutting subsequent query size dramatically. Avoid table calculations on large datasets; they run post-query in Tableau's engine, not the DB.$escape$,
  $escape$-- Materialized view for a slow Tableau live connection
CREATE MATERIALIZED VIEW mv_sales_summary AS
SELECT
    d.region,
    d.category,
    d.order_date::DATE AS order_date,
    SUM(f.sales)        AS total_sales,
    SUM(f.profit)       AS total_profit,
    COUNT(f.order_id)   AS order_count
FROM fact_orders f
JOIN dim_product d ON f.product_key = d.product_key
GROUP BY d.region, d.category, d.order_date::DATE;

-- Refresh on a schedule aligned to Tableau extract refresh cadence
REFRESH MATERIALIZED VIEW CONCURRENTLY mv_sales_summary;$escape$,
