INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'eb30d8e6-79a1-4791-b1f3-168ccc327dbf',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tableau Mobile Dashboards — What Actually Works on Small Screens$escape$,
  $escape$Tableau's Device Designer (Dashboard → Device Layouts) lets you create Phone and Tablet layouts from a single workbook. Each layout is independent — you can hide sheets, reorder objects, and resize containers without touching the Default view. Use Automatic sizing on the Phone layout, not Fixed; Fixed layouts force horizontal scrolling on most devices. Tiled layouts outperform floating on mobile — floating objects don't reflow, so they overlap unpredictably below 375px width. Strip non-essential views: if a bar chart and a summary KPI tile convey the same insight, keep only the KPI on Phone layout. Use Show/Hide Button containers to collapse filters rather than stacking them vertically. Avoid dense crosstabs entirely — they're unusable on touch screens. For marks, bump minimum mark size to 14px via Format → Marks to hit touch targets. Dashboard Actions using Highlight (not Filter) preserve context without navigating away, which is critical when back-navigation on mobile is expensive. Publish to Tableau Server/Cloud and test via the Tableau Mobile app — the browser preview in Desktop lies about touch behavior.$escape$,
  NULL,
  NULL,
