INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '715a91ba-723e-4e62-b194-6a9e62f37d48',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tableau Embedding API v3 — SSO, White-Labeling, and Ditching iFrames$escape$,
  $escape$Tableau's legacy iFrame embed passes a `?:embed=yes` URL param and relies on Trusted Authentication — a server-to-server ticket exchange that's brittle and deprecated. The modern path is the Embedding API v3 (`@tableau/embedding-api`), which exposes a `<tableau-viz>` web component backed by a proper JavaScript SDK. For SSO, replace Trusted Auth tickets with Connected Apps JWTs: register a Connected App in Tableau Server/Cloud, sign a HS256 JWT with `sub` (username), `scp: ['tableau:views:embed']`, `iss` (client ID), and `kid` (secret ID). Pass it as the `token` attribute — no server round-trip per user, just token refresh. White-labeling is handled via `toolbar="hidden"`, `hideTabs`, and `customViews="hidden"` attributes directly on the component. For deeper CSS control, Tableau Cloud supports Custom Fonts and zone-level styling, but DOM injection into the viz iframe is blocked by CSP. Critically, Embedding API v3 exposes `addEventListener` for `FilterChanged`, `MarksSelected`, and `FirstInteractive` — none of which are accessible in raw iFrame mode. Use the SDK; iFrame embedding is a dead end.$escape$,
  $escape$import { TableauViz, TableauEventType } from '@tableau/embedding-api';
import jwt from 'jsonwebtoken';

// Server-side: generate Connected Apps JWT
function getTableauToken(clientId: string, secretId: string, secret: string, username: string) {
  return jwt.sign(
    { sub: username, scp: ['tableau:views:embed'] },
    secret,
    { algorithm: 'HS256', issuer: clientId, keyid: secretId, expiresIn: '5m' }
  );
}

// Client-side: mount whitelabeled viz
const viz = new TableauViz();
viz.src = 'https://tableau.company.com/views/SalesDashboard/Overview';
viz.token = await fetch('/api/tableau-token').then(r => r.text());
viz.toolbar = 'hidden';
viz.hideTabs = true;
document.getElementById('embed-root')!.appendChild(viz);
viz.addEventListener(TableauEventType.FirstInteractive, () => console.log('ready'));$escape$,
  $escape$typescript$escape$,
