INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '63347bb0-11d8-4b92-8454-9ef041464eaf',
  '00000000-0000-0000-0000-000000000001',
  $escape$Tableau Alerting — Threshold Alerts, Pulse Anomaly Detection, and Webhook Channels$escape$,
  $escape$Tableau's data-driven alerts fire when a mark's value crosses a condition you define directly on a published view. Open any viz on Tableau Server or Cloud, click the bell icon on an axis, set your operator (greater than, less than, equal to), and Tableau polls the underlying data source on your chosen frequency. Recipients get an email with a snapshot of the triggering view—no ETL pipeline required.

For anomaly detection without manual threshold tuning, Tableau Pulse (Cloud-only) uses Einstein AI to monitor connected metrics and surface unexpected shifts proactively. It delivers digests to Slack or email when values deviate from learned baselines—no calculated field gymnastics needed.

For custom notification routing, Tableau Server and Cloud expose webhooks that fire on events like `datasource-refresh-succeeded` and `view-created`. POST these payloads to a relay service to fan out into PagerDuty, Microsoft Teams, or custom Slack channels. The `tableauserverclient` (TSC) Python library gives you programmatic control over data alerts—critical when migrating alert rules across dozens of workbooks or auditing which alerts are still actively owned.$escape$,
  $escape$import tableauserverclient as TSC

server = TSC.Server("https://your-tableau-server", use_server_version=True)
auth = TSC.PersonalAccessTokenAuth("token_name", "token_secret", site_id="your-site")

with server.auth.sign_in(auth):
    all_alerts, _ = server.data_alerts.get()

    for alert in all_alerts:
        print(f"{alert.subject} | owner={alert.owner_id} | freq={alert.frequency}")

    # Prune alerts owned by departed users or marked deprecated
    stale = [a for a in all_alerts if "deprecated" in a.subject.lower()]
    for alert in stale:
        server.data_alerts.delete(alert.id)
        print(f"Deleted: {alert.subject}")$escape$,
  $escape$python$escape$,
